<template>
  <router-link
    :to="targetRoute"
    v-if="
      isLink &&
      productionId &&
      !isCurrentUserClient &&
      taskType.for_entity !== 'Concept'
    "
  >
    <span
      class="tag task-type-name"
      :class="{
        rounded
      }"
      :title="title"
    >
      {{ taskType.name }}
    </span>
  </router-link>
  <div
    class="tag task-type-name no-link"
    :class="{
      deletable,
      canceled: disable,
      rounded,
      thin: thin
    }"
    v-else
  >
    <span :title="title">
      {{ taskType.name }}
    </span>
    <span class="delete-times" v-if="deletable" @click="$emit('delete')">
      ×
    </span>
  </div>
</template>

<script>
import { mapGetters } from 'vuex'

import { pluralizeEntityType } from '@/lib/path'

export default {
  name: 'task-type-name',

  props: {
    isLink: {
      type: Boolean,
      default: true
    },
    deletable: {
      type: Boolean,
      default: false
    },
    disable: {
      type: Boolean,
      default: false
    },
    productionId: {
      type: String,
      default: null
    },
    rounded: {
      type: Boolean,
      default: false
    },
    taskId: {
      type: String,
      default: null
    },
    taskType: {
      type: Object,
      default: null
    },
    thin: {
      type: Boolean,
      default: false
    },
    transparent: {
      type: Boolean,
      default: false
    }
  },

  emits: ['delete'],

  computed: {
    ...mapGetters(['isCurrentUserClient']),

    color() {
      return this.taskType.color?.toUpperCase() === '#000000'
        ? '#666'
        : this.taskType.color
    },

    title() {
      return `${this.taskType.for_entity} / ${this.taskType.name}`
    },

    targetRoute() {
      if (this.taskId) {
        if (this.$route.params.episode_id) {
          return {
            name: 'episode-task',
            params: {
              production_id: this.productionId,
              task_id: this.taskId,
              episode_id: this.$route.params.episode_id,
              type: pluralizeEntityType(this.taskType.for_entity)
            }
          }
        } else {
          return {
            name: 'task',
            params: {
              production_id: this.productionId,
              task_id: this.taskId,
              type: pluralizeEntityType(this.taskType.for_entity)
            }
          }
        }
      } else if (this.taskType.for_entity === 'Episode') {
        return {
          name: 'episodes-task-type',
          params: {
            production_id: this.productionId,
            task_type_id: this.taskType.id
          }
        }
      } else {
        const route = {
          name: 'task-type',
          params: {
            production_id: this.productionId,
            task_type_id: this.taskType.id,
            type: pluralizeEntityType(this.taskType.for_entity)
          }
        }

        if (this.taskType.episode_id || this.$route.params.episode_id) {
          route.name = 'episode-task-type'
          route.params.episode_id =
            this.taskType.episode_id || this.$route.params.episode_id
        }
        return route
      }
    }
  }
}
</script>

<style lang="scss" scoped>
.tag {
  border-left: 4px solid v-bind(color);
  border-radius: 0;
  color: var(--text);
  font-size: 0.9em;
  font-weight: 600;
  line-height: 0.8em;
  padding: 0 0.7em;
  margin: 0;

  &.deletable {
    padding-right: 0;
  }

  &.rounded {
    border-top-right-radius: 5px;
    border-bottom-right-radius: 5px;
  }

  &.thin {
    font-size: 0.7em;
    line-height: 0.6em;
    padding: 0 0.5em;
  }

  .dark & {
    background: $dark-grey-lightest;
  }
}

.delete-times {
  cursor: pointer;
  font-size: 1.2rem;
  font-weight: bold;
  padding-left: 7px;
  padding-bottom: 2px;
  padding-right: 0.7rem;

  &:hover {
    color: $black;
  }
}

.no-link {
  color: var(--text);
  cursor: default;
}
</style>
